    r.add_lower_bounded_number_option("max_cpu_time", "Maximum number of CPU seconds.", 0.0, true, 1e20, "A limit on CPU seconds that Ipopt can use to solve one problem. If during the convergence check this limit is exceeded, Ipopt will terminate with a corresponding message.")?;
    r.add_lower_bounded_number_option("dual_inf_tol", "Desired threshold for the dual infeasibility.", 0.0, true, 1.0, "Absolute tolerance on the dual infeasibility. Successful termination requires that the max-norm of the (unscaled) dual infeasibility is less than this threshold.")?;
    r.add_lower_bounded_number_option("constr_viol_tol", "Desired threshold for the constraint and variable bound violation.", 0.0, true, 1e-4, "Absolute tolerance on the constraint and variable bound violation. Successful termination requires that the max-norm of the (unscaled) constraint violation is less than this threshold. If option bound_relax_factor is not zero 0, then Ipopt relaxes given variable bounds. The value of constr_viol_tol is used to restrict the absolute amount of this bound relaxation. ")?;
    r.add_lower_bounded_number_option("compl_inf_tol", "Desired threshold for the complementarity conditions.", 0.0, true, 1e-4, "Absolute tolerance on the complementarity. Successful termination requires that the max-norm of the (unscaled) complementarity is less than this threshold.")?;
    r.add_lower_bounded_number_option("acceptable_tol", "\"Acceptable\" convergence tolerance (relative).", 0.0, true, 1e-6, "Determines which (scaled) overall optimality error is considered to be \"acceptable\". There are two levels of termination criteria. If the usual \"desired\" tolerances (see tol, dual_inf_tol etc) are satisfied at an iteration, the algorithm immediately terminates with a success message. On the other hand, if the algorithm encounters \"acceptable_iter\" many iterations in a row that are considered \"acceptable\", it will terminate before the desired convergence tolerance is met. This is useful in cases where the algorithm might not be able to achieve the \"desired\" level of accuracy.")?;
    r.add_lower_bounded_integer_option("acceptable_iter", "Number of \"acceptable\" iterates before triggering termination.", 0, 15, "If the algorithm encounters this many successive \"acceptable\" iterates (see \"acceptable_tol\"), it terminates, assuming that the problem has been solved to best possible accuracy given round-off. If it is set to zero, this heuristic is disabled.")?;
    r.add_lower_bounded_number_option("acceptable_dual_inf_tol", "\"Acceptance\" threshold for the dual infeasibility.", 0.0, true, 1e10, "Absolute tolerance on the dual infeasibility. \"Acceptable\" termination requires that the (max-norm of the unscaled) dual infeasibility is less than this threshold; see also acceptable_tol.")?;
    r.add_lower_bounded_number_option("acceptable_constr_viol_tol", "\"Acceptance\" threshold for the constraint violation.", 0.0, true, 1e-2, "Absolute tolerance on the constraint violation. \"Acceptable\" termination requires that the max-norm of the (unscaled) constraint violation is less than this threshold; see also acceptable_tol.")?;
    r.add_lower_bounded_number_option("acceptable_compl_inf_tol", "\"Acceptance\" threshold for the complementarity conditions.", 0.0, true, 1e-2, "Absolute tolerance on the complementarity. \"Acceptable\" termination requires that the max-norm of the (unscaled) complementarity is less than this threshold; see also acceptable_tol.")?;
    r.add_lower_bounded_number_option("acceptable_obj_change_tol", "\"Acceptance\" stopping criterion based on objective function change.", 0.0, false, 1e20, "If the relative change of the objective function (scaled by Max(1,|f(x)|)) is less than this value, this part of the acceptable tolerance termination is satisfied; see also acceptable_tol. This is useful for the quasi-Newton option, which has trouble to bring down the dual infeasibility.")?;
    r.add_lower_bounded_number_option("diverging_iterates_tol", "Threshold for maximal value of primal iterates.", 0.0, true, 1e20, "If any component of the primal iterates exceeded this value (in absolute terms), the optimization is aborted with the exit message that the iterates seem to be diverging.")?;
    r.add_lower_bounded_number_option("mu_target", "Desired value of complementarity.", 0.0, false, 0.0, "Usually, the barrier parameter is driven to zero and the termination test for complementarity is measured with respect to zero complementarity. However, in some cases it might be desired to have Ipopt solve barrier problem for strictly positive value of the barrier parameter. In this case, the value of \"mu_target\" specifies the final value of the barrier parameter, and the termination tests are then defined with respect to the barrier problem for this value of the barrier parameter.")?;
    // Rapid infeasibility detection (pounce addition) — a main-loop
    // analogue of Ipopt's restoration-side LOCALLY_INFEASIBLE test.
    r.add_lower_bounded_number_option("infeas_stationarity_tol", "Stationarity tolerance for rapid infeasibility detection.", 0.0, false, 1e-8, "The main loop terminates with local infeasibility when the scaled infeasibility stationarity norm(J^T c) / max(1, norm(c)) stays at or below this value, while the constraint violation stays bounded away from zero (see infeas_viol_kappa), for infeas_max_streak successive iterations. Setting this to 0 disables rapid infeasibility detection.")?;
    r.add_lower_bounded_number_option("infeas_viol_kappa", "Constraint-violation margin for rapid infeasibility detection.", 0.0, false, 1e2, "An iterate only counts toward the infeasibility streak when its max-norm constraint violation exceeds this multiple of constr_viol_tol. Keeps rapid infeasibility detection from firing on nearly-feasible flat spots.")?;
    r.add_lower_bounded_integer_option("infeas_max_streak", "Successive infeasible-stationary iterations before declaring local infeasibility.", 0, 5, "Number of consecutive iterations that must satisfy the rapid infeasibility detection test before the main loop terminates with local infeasibility. Setting this to 0 disables rapid infeasibility detection.")?;
    // Status-fidelity gate (pounce addition, pounce#173) — a post-solve
    // relabel for consumers (e.g. discopt's safe bound tightening) that
    // must not trust an OPTIMAL status on a drifted point.
    r.add_lower_bounded_number_option("obj_scale_certificate_threshold", "Objective-scale floor below which a termination certificate is re-tested rather than trusted.", 0.0, false, 1e-4, "DELIBERATE DEVIATION FROM UPSTREAM IPOPT (pounce#200). Gradient-based objective scaling can pick a factor so small (floored at nlp_scaling_min_value, 1e-8) that the scaled convergence test passes far from any KKT point: on the flat quartics quartc/dqrtic the solver certified optimality at objective 248.88 / 39.36 when the true minimum is ~0, with an unscaled dual infeasibility of 0.84. When the objective scaling factor is below this threshold AND the max-norm UNSCALED KKT error is still above acceptable_tol, POUNCE does not stop; it keeps iterating. A constant objective scale cancels out of the Newton step and the line-search tests are scale-invariant, so the run continues along the trajectory an unscaled run would take, and on a genuinely false stop it reaches the true minimum (quartc then finishes at 8.8e-07). Whether the stop was really false is NOT predicted in advance -- it is tested: if continuing achieves nothing, the refused point is restored and reported with the status it would originally have had, so the outcome is never worse than without the mechanism. Set to 0 to disable and restore bit-for-bit upstream behaviour (Ipopt itself reports quartc at 248.88 as optimal). Distinct from kkt_fidelity_tol, which is a pure relabel at termination and does not change the iteration path.")?;
    r.add_lower_bounded_number_option("kkt_fidelity_tol", "Post-solve max-norm unscaled KKT error above which Solve_Succeeded is downgraded.", 0.0, false, 0.0, "Opt-in status-fidelity check (default 0 = disabled). When positive, after the solve a reported Solve_Succeeded whose max-norm UNSCALED KKT error (max of the unscaled dual infeasibility, constraint violation, and complementarity, reported as final_unscaled_kkt_error) exceeds this threshold is downgraded to Solved_To_Acceptable_Level. This is a pure relabel at termination — it does not change the iteration path or make the solver work harder; to instead drive the solver to a tighter point, tighten dual_inf_tol / constr_viol_tol / compl_inf_tol, which gate on the same unscaled residuals. Useful when the default (scaled) convergence test passes on an ill-conditioned, nlp_scaling-deflated problem but the user-space duals have drifted.")?;

    // ===== OrigIpoptNLP::RegisterOptions (Algorithm/IpOrigIpoptNLP.cpp) =====
    r.set_registering_category("NLP");
    r.add_lower_bounded_number_option("bound_relax_factor", "Factor for initial relaxation of the bounds.", 0.0, false, 1e-8, "Before start of the optimization, the bounds given by the user are relaxed. This option sets the factor for this relaxation. Additional, the constraint violation tolerance constr_viol_tol is used to bound the relaxation by an absolute value. If it is set to zero, then then bounds relaxation is disabled. See Eqn.(35) in implementation paper. Note that the constraint violation reported by Ipopt at the end of the solution process does not include violations of the original (non-relaxed) variable bounds. See also option honor_original_bounds.")?;
    r.add_bool_option("honor_original_bounds", "Indicates whether final points should be projected into original bounds.", false, "Ipopt might relax the bounds during the optimization (see, e.g., option \"bound_relax_factor\"). This option determines whether the final point should be projected back into the user-provide original bounds after the optimization. Note that violations of constraints and complementarity reported by Ipopt at the end of the solution process are for the non-projected point.")?;
    r.set_registering_category("Warm Start");
    r.add_bool_option("warm_start_same_structure", "Indicates whether a problem with a structure identical to the previous one is to be solved.", false, "If enabled, then the algorithm assumes that an NLP is now to be solved whose structure is identical to one that already was considered (with the same NLP object).")?;
    // Upstream registers `warm_start_init_point` in
    // `IpDefaultIterateInitializer.cpp:RegisterOptions`, alongside the
    // regular (cold) initializer. Pounce's `DefaultIterateInitializer`
    // doesn't pull it from `OptionsList` directly — `AlgBuilder` reads
    // it to pick between `DefaultIterateInitializer` and
    // `WarmStartIterateInitializer` — but the option still needs to
    // appear in the registry so `--option warm_start_init_point=yes`
    // type-checks.
    r.add_bool_option("warm_start_init_point", "Warm-start for initial point", false, "Indicates whether this optimization should use a warm start initialization, where values of primal and dual variables are given (e.g., from a previous optimization of a related problem.)")?;
    r.set_registering_category("NLP");
    r.add_bool_option("check_derivatives_for_naninf", "Indicates whether it is desired to check for Nan/Inf in derivative matrices", false, "Activating this option will cause an error if an invalid number is detected in the constraint Jacobians or the Lagrangian Hessian. If this is not activated, the test is skipped, and the algorithm might proceed with invalid numbers and fail. If test is activated and an invalid number is detected, the matrix is written to output with print_level corresponding to J_MOREDETAILED (7); so beware of large output!")?;
    r.add_bool_option("grad_f_constant", "Indicates whether to assume that the objective function is linear", false, "Activating this option will cause Ipopt to ask for the Gradient of the objective function only once from the NLP and reuse this information later.")?;
    r.add_bool_option("jac_c_constant", "Indicates whether to assume that all equality constraints are linear", false, "Activating this option will cause Ipopt to ask for the Jacobian of the equality constraints only once from the NLP and reuse this information later.")?;
    r.add_bool_option("jac_d_constant", "Indicates whether to assume that all inequality constraints are linear", false, "Activating this option will cause Ipopt to ask for the Jacobian of the inequality constraints only once from the NLP and reuse this information later.")?;
    r.add_bool_option("hessian_constant", "Indicates whether to assume the problem is a QP (quadratic objective, linear constraints)", false, "Activating this option will cause Ipopt to ask for the Hessian of the Lagrangian function only once from the NLP and reuse this information later.")?;
    r.set_registering_category("Hessian Approximation");
    r.add_string_option("hessian_approximation", "Indicates what Hessian information is to be used.", "exact", &[("exact", "Use second derivatives provided by the NLP."), ("limited-memory", "Perform a limited-memory quasi-Newton approximation")], "This determines which kind of information for the Hessian of the Lagrangian function is used by the algorithm.")?;
    r.add_string_option(
        "hessian_approximation_space",
        "Indicates in which subspace the Hessian information is to be approximated.",
        "nonlinear-variables",
        &[
            (
                "nonlinear-variables",
                "only in space of nonlinear variables.",
            ),
            (
                "all-variables",
                "in space of all variables (without slacks)",
            ),
        ],
        "",
    )?;

    // ===== OrigIterationOutput::RegisterOptions (Algorithm/IpOrigIterationOutput.cpp) =====
    r.set_registering_category("Output");
    r.set_registering_category("Output");
    r.add_bool_option("print_info_string", "Enables printing of additional info string at end of iteration output.", false, "This string contains some insider information about the current iteration. For details, look for \"Diagnostic Tags\" in the Ipopt documentation.")?;
    r.add_string_option("inf_pr_output", "Determines what value is printed in the \"inf_pr\" output column.", "original", &[("internal", "max-norm of violation of internal equality constraints"), ("original", "maximal constraint violation in original NLP")], "Ipopt works with a reformulation of the original problem, where slacks are introduced and the problem might have been scaled. The choice \"internal\" prints out the constraint violation of this formulation. With \"original\" the true constraint violation in the original NLP is printed.")?;
    r.add_lower_bounded_integer_option("print_frequency_iter", "Determines at which iteration frequency the summarizing iteration output line should be printed.", 1, 1, "Summarizing iteration output is printed every print_frequency_iter iterations, if at least print_frequency_time seconds have passed since last output.")?;
    r.add_lower_bounded_number_option("print_frequency_time", "Determines at which time frequency the summarizing iteration output line should be printed.", 0.0, false, 0.0, "Summarizing iteration output is printed if at least print_frequency_time seconds have passed since last output and the iteration number is a multiple of print_frequency_iter.")?;
    r.set_registering_category("");

