    r.add_bool_option("fast_step_computation", "Indicates if the linear system should be solved quickly.", false, "If enabled, the algorithm assumes that the linear system that is solved to obtain the search direction is solved sufficiently well. In that case, no residuals are computed to verify the solution and the computation of the search direction is a little faster.")?;

    // ===== PDFullSpaceSolver::RegisterOptions (Algorithm/IpPDFullSpaceSolver.cpp) =====
    r.set_registering_category("Step Calculation");
    r.add_lower_bounded_integer_option("min_refinement_steps", "Minimum number of iterative refinement steps per linear system solve.", 0, 1, "Iterative refinement (on the full unsymmetric system) is performed for each right hand side. This option determines the minimum number of iterative refinements (i.e. at least \"min_refinement_steps\" iterative refinement steps are enforced per right hand side.)")?;
    r.add_lower_bounded_integer_option("max_refinement_steps", "Maximum number of iterative refinement steps per linear system solve.", 0, 10, "Iterative refinement (on the full unsymmetric system) is performed for each right hand side. This option determines the maximum number of iterative refinement steps.")?;
    r.add_lower_bounded_number_option("residual_ratio_max", "Iterative refinement tolerance", 0.0, true, 1e-10, "Iterative refinement is performed until the residual test ratio is less than this tolerance (or until \"max_refinement_steps\" refinement steps are performed).")?;
    r.add_lower_bounded_number_option("residual_ratio_singular", "Threshold for declaring linear system singular after failed iterative refinement.", 0.0, true, 1e-5, "If the residual test ratio is larger than this value after failed iterative refinement, the algorithm pretends that the linear system is singular.")?;
    r.add_lower_bounded_number_option("residual_improvement_factor", "Minimal required reduction of residual test ratio in iterative refinement.", 0.0, true, 0.999999999, "If the improvement of the residual test ratio made by one iterative refinement step is not better than this factor, iterative refinement is aborted.")?;
    r.add_lower_bounded_number_option("neg_curv_test_tol", "Tolerance for heuristic to ignore wrong inertia.", 0.0, false, 0.0, "If nonzero, incorrect inertia in the augmented system is ignored, and Ipopt tests if the direction is a direction of positive curvature. This tolerance is alpha_n in the paper by Zavala and Chiang (2014) and it determines when the direction is considered to be sufficiently positive. A value in the range of [1e-12, 1e-11] is recommended.")?;
    r.add_string_option("neg_curv_test_reg", "Whether to do the curvature test with the primal regularization (see Zavala and Chiang, 2014).", "yes", &[("yes", "use primal regularization with the inertia-free curvature test"), ("no", "use original IPOPT approach, in which the primal regularization is ignored")], "")?;

    // ===== PDPerturbationHandler::RegisterOptions (Algorithm/IpPDPerturbationHandler.cpp) =====
    r.set_registering_category("Step Calculation");
    r.add_lower_bounded_number_option("max_hessian_perturbation", "Maximum value of regularization parameter for handling negative curvature.", 0.0, true, 1e20, "In order to guarantee that the search directions are indeed proper descent directions, Ipopt requires that the inertia of the (augmented) linear system for the step computation has the correct number of negative and positive eigenvalues. The idea is that this guides the algorithm away from maximizers and makes Ipopt more likely converge to first order optimal points that are minimizers. If the inertia is not correct, a multiple of the identity matrix is added to the Hessian of the Lagrangian in the augmented system. This parameter gives the maximum value of the regularization parameter. If a regularization of that size is not enough, the algorithm skips this iteration and goes to the restoration phase. This is delta_w^max in the implementation paper.")?;
    r.add_lower_bounded_number_option("min_hessian_perturbation", "Smallest perturbation of the Hessian block.", 0.0, false, 1e-20, "The size of the perturbation of the Hessian block is never selected smaller than this value, unless no perturbation is necessary. This is delta_w^min in implementation paper.")?;
    r.add_lower_bounded_number_option("perturb_inc_fact_first", "Increase factor for x-s perturbation for very first perturbation.", 1.0, true, 100.0, "The factor by which the perturbation is increased when a trial value was not sufficient - this value is used for the computation of the very first perturbation and allows a different value for the first perturbation than that used for the remaining perturbations. This is bar_kappa_w^+ in the implementation paper.")?;
    r.add_lower_bounded_number_option("perturb_inc_fact", "Increase factor for x-s perturbation.", 1.0, true, 8.0, "The factor by which the perturbation is increased when a trial value was not sufficient - this value is used for the computation of all perturbations except for the first. This is kappa_w^+ in the implementation paper.")?;
    r.add_bounded_number_option("perturb_dec_fact", "Decrease factor for x-s perturbation.", 0.0, true, 1.0, true, 1.0 / 3.0, "The factor by which the perturbation is decreased when a trial value is deduced from the size of the most recent successful perturbation. This is kappa_w^- in the implementation paper.")?;
    r.add_lower_bounded_number_option("first_hessian_perturbation", "Size of first x-s perturbation tried.", 0.0, true, 1e-4, "The first value tried for the x-s perturbation in the inertia correction scheme. This is delta_0 in the implementation paper.")?;
    r.add_lower_bounded_number_option(
        "jacobian_regularization_value",
        "Size of the regularization for rank-deficient constraint Jacobians.",
        0.0,
        false,
        1e-8,
        "This is bar delta_c in the implementation paper.",
    )?;
    r.add_lower_bounded_number_option(
        "jacobian_regularization_exponent",
        "Exponent for mu in the regularization for rank-deficient constraint Jacobians.",
        0.0,
        false,
        0.25,
        "This is kappa_c in the implementation paper.",
    )?;
    r.add_bool_option("perturb_always_cd", "Active permanent perturbation of constraint linearization.", false, "Enabling this option leads to using the delta_c and delta_d perturbation for the computation of every search direction. Usually, it is only used when the iteration matrix is singular.")?;

    // ===== QualityFunctionMuOracle::RegisterOptions (Algorithm/IpQualityFunctionMuOracle.cpp) =====
    r.set_registering_category("Barrier Parameter Update");
    r.add_lower_bounded_number_option("sigma_max", "Maximum value of the centering parameter.", 0.0, true, 1e2, "This is the upper bound for the centering parameter chosen by the quality function based barrier parameter update. Only used if option \"mu_oracle\" is set to \"quality-function\".")?;
    r.add_lower_bounded_number_option("sigma_min", "Minimum value of the centering parameter.", 0.0, false, 1e-6, "This is the lower bound for the centering parameter chosen by the quality function based barrier parameter update. Only used if option \"mu_oracle\" is set to \"quality-function\".")?;
    r.add_string_option(
        "quality_function_norm_type",
        "Norm used for components of the quality function.",
        "2-norm-squared",
        &[
            ("1-norm", "use the 1-norm (abs sum)"),
            ("2-norm-squared", "use the 2-norm squared (sum of squares)"),
            ("max-norm", "use the infinity norm (max)"),
            ("2-norm", "use 2-norm"),
        ],
        "Only used if option \"mu_oracle\" is set to \"quality-function\".",
    )?;
    r.add_string_option("quality_function_centrality", "The penalty term for centrality that is included in quality function.", "none", &[("none", "no penalty term is added"), ("log", "complementarity * the log of the centrality measure"), ("reciprocal", "complementarity * the reciprocal of the centrality measure"), ("cubed-reciprocal", "complementarity * the reciprocal of the centrality measure cubed")], "This determines whether a term is added to the quality function to penalize deviation from centrality with respect to complementarity. The complementarity measure here is the xi in the Loqo update rule. Only used if option \"mu_oracle\" is set to \"quality-function\".")?;
    r.add_string_option("quality_function_balancing_term", "The balancing term included in the quality function for centrality.", "none", &[("none", "no balancing term is added"), ("cubic", "Max(0,Max(dual_inf,primal_inf)-compl)^3")], "This determines whether a term is added to the quality function that penalizes situations where the complementarity is much smaller than dual and primal infeasibilities. Only used if option \"mu_oracle\" is set to \"quality-function\".")?;
    r.add_lower_bounded_integer_option("quality_function_max_section_steps", "Maximum number of search steps during direct search procedure determining the optimal centering parameter.", 0, 8, "The golden section search is performed for the quality function based mu oracle. Only used if option \"mu_oracle\" is set to \"quality-function\".")?;
    r.add_bounded_number_option("quality_function_section_sigma_tol", "Tolerance for the section search procedure determining the optimal centering parameter (in sigma space).", 0.0, false, 1.0, true, 1e-2, "The golden section search is performed for the quality function based mu oracle. Only used if option \"mu_oracle\" is set to \"quality-function\".")?;
    r.add_bounded_number_option("quality_function_section_qf_tol", "Tolerance for the golden section search procedure determining the optimal centering parameter (in the function value space).", 0.0, false, 1.0, true, 0.0, "The golden section search is performed for the quality function based mu oracle. Only used if option \"mu_oracle\" is set to \"quality-function\".")?;
    // Pounce-specific (pounce#58) guard on the probing μ-oracle's
    // input iterate. No upstream Ipopt counterpart.
    r.add_lower_bounded_number_option("probing_iterate_quality_factor", "Iterate-quality guard for the probing (Mehrotra) mu oracle.", 0.0, false, 1e4, "If curr_avrg_compl / curr_mu exceeds this factor the probing oracle is skipped and a restoration request is signalled, because a 5+ order ratio would otherwise cause the oracle's sigma*mu_curr to throw the iterate out of the convergence neighborhood. Default 1e4. Set to 0 to disable (matches pre-pounce#58 behaviour). Only consumed when mu_oracle=probing (the default under mehrotra_algorithm=yes).")?;

