    r.add_lower_bounded_number_option("constr_mult_reset_threshold", "Threshold for resetting equality and inequality multipliers after restoration phase.", 0.0, false, 0.0, "After returning from the restoration phase, the constraint multipliers are recomputed by a least square estimate. This option triggers when those least-square estimates should be ignored.")?;
    r.add_lower_bounded_number_option("resto_failure_feasibility_threshold", "Threshold for primal infeasibility to declare failure of restoration phase.", 0.0, false, 0.0, "If the restoration phase is terminated because of the \"acceptable\" termination criteria and the primal infeasibility is smaller than this value, the restoration phase is declared to have failed. The default value is actually 1e2*tol, where tol is the general termination tolerance.")?;

